	.TITLE	NEWRASTER	.PROC	M680002	.REF	SMAKY	.LOC	0OPDDIS:	.BLKB	4LGVAR:	.LOC	0START:	LOAD.L	A6,#R16"VAR	LIB	?GCHDIS		; D6 <-- canal cran	LOAD.W	D3,#TYPWDO	; D3 <-- type fentre cran	LOAD.L	D4,#4		; D4 <-- longueur demande	LOAD.L	A4,#(A6)+OPDDIS	; A4 <-- ^buffer	FOS	?RSTATUS	; demande le ^rel !	LOAD.L	A2,(A6)+OPDDIS	CLR.L	D3	LIB	?SETCURS	LIB	?AFTIM	.B	NOCURS,EOP	.ASCII	"ABCDEFGHIJKLMNOPQRSTUVWXYZ<CR>"	.ASCII	"abcdefghijklmnopqrstuvwxyz<CR>"	.ASCII	"ABCDEFGHIJKLMNOPQRSTUVWXYZ<CR>"	.ASCII	"abcdefghijklmnopqrstuvwxyz<CR>"	.B	0	.EVEN	LOAD.L	D3,#-1	LOAD.L	D4,#-1	LIB	?DRMDEF	LOAD.L	D0,#H'10000*100+0LOOP:	LOAD.L	D3,#H'10000*100+0	LOAD.L	D4,#H'10000*100+200	LOAD.W	D2,#SETDOT	LIB	?DRMATRIX	LOAD.L	A3,#0		; source	LOAD.L	D3,#H'10000*0+0	LOAD.L	A4,#0		; destination	LOAD.L	D4,D0	LOAD.L	D2,#H'10000*28+10	CALL	RASTER_CLEAR	LIB	?GETCAR	COMP.W	D3,#END	JUMP,EQ FIN	INC.W	D0	SWAP.W	D0	INC.W	D0	SWAP.W	D0	JUMP	LOOPFIN:	EXIT;------------\; RASTER_LOAD >;============/; Dplace une surface rectangulaire mmoire/cran --> mmoire/cran.; in	A2.L	^description fentre;	----;	D3.L	coordonne source (y;x);	A3.L	^mmoire source/^nil si cran;	D5.W	Iy source (si mmoire);	----;	D4.L	coordonne destination (y;x);	A4.L	^mmoire destination/^nil si cran;	D6.W	Iy destination (si mmoire);	----;	D2.L	hauteur/largeur (y;x); out	-; mod	-RASTER_LOAD:	PUSHM.L	D0..D7,A0..A6	LOAD.L	D0,A3		; source dans l'cran ?	JUMP',NE 10$		; non => 10$				; oui =>	LOAD.L	A3,(A2)+ODFABS	; A3 <-- adresse dbut cran	LOAD.W	D5,(A2)+ODFIIY	; D5 <-- Iy cran	ADD.W	D3,(A2)+ODFWBX	; D3 <-- dans (sous-)fentre en X	SWAP.W	D3	ADD.W	D3,(A2)+ODFWBY	; D3 <-- dans (sous-)fentre en Y	SWAP.W	D310$:	LOAD.L	D0,D3	SWAP.W	D0	MUL.WU	D0,D5	ADD.L	A3,D0	LOAD.W	D0,D3	SR.W	D0,#3	ADD.W	A3,D0		; A3 <-- ^byte source	AND.W	D3,#H'0007	; D3 <-- Ds	LOAD.W	A5,D5		; A5 <-- Iy source	LOAD.L	D0,A4		; destination dans l'cran ?	JUMP',NE 15$		; non => 15$				; oui =>	LOAD.L	A4,(A2)+ODFABS	; A4 <-- adresse dbut cran	LOAD.W	D6,(A2)+ODFIIY	; D6 <-- Iy cran	ADD.W	D4,(A2)+ODFWBX	; D4 <-- dans (sous-)fentre en X	SWAP.W	D4	ADD.W	D4,(A2)+ODFWBY	; D4 <-- dans (sous-)fentre en Y	SWAP.W	D415$:	LOAD.L	D0,D4	SWAP.W	D0	MUL.WU	D0,D6	ADD.L	A4,D0	LOAD.W	D0,D4	SR.W	D0,#3	ADD.W	A4,D0		; A4 <-- ^byte destination	AND.W	D4,#H'0007	; D4 <-- Dd	LOAD.W	A6,D6		; A6 <-- Iy destination	LOAD.L	A1,#R16"TARASTER_MASK20$:	PUSHM.L	D2,D3,D4,A3,A4; Si l'adresse n'est pas paire, recule d'un byte.	LOAD.W	D0,A3	RR.W	D0,#1	JUMP',CC 30$	DEC.L	A3		; A3 <-- adresse paire	ADD.W	D3,#8		; D3 <-- Ds30$:	LOAD.W	D0,A4	RR.W	D0,#1	JUMP',CC 32$	DEC.L	A4		; A4 <-- adresse paire	ADD.W	D4,#8		; D4 <-- Dd32$:; Effectue le travail de dbut.	LOAD.W	D0,D3	OR.W	D0,D4	JUMP',NE 40$	COMP.W	D2,#16	JUMP,LO 70$	JUMP	50$40$:	LOAD.W	D0,D4	SL.W	D0,#1	LOAD.W	D5,(A1)+(D0.W)	; D5 <-- masque	LOAD.W	D1,D4	SUB.W	D4,D3		; D4 <-- Dm	JUMP',HS 44$	ADD.W	D4,#16		; D4 <-- Dm	LOAD.W	D0,(A3+)	SWAP.W	D044$:	ADD.W	D2,D1	SUB.W	D2,#16		; D2 <-- largeur restante	JUMP,LO 72$	LOAD.W	D0,(A3+)	LOAD.L	D1,D0	RR.L	D1,D4	AND.W	D1,D5	NOT.W	D5	LOAD.W	D3,(A4)	AND.W	D3,D5	OR.W	D1,D3	LOAD.W	(A4+),D1	; destination <-- dbut	SWAP.W	D0; Effectue le travail du milieu.50$:	LOAD.W	D3,D2	SR.W	D3,#4		; D3 <-- nb de words	JUMP',EQ 60$	DEC.W	D3		; D3 <-- -1  cause NMO52$:	LOAD.W	D0,(A3+)	LOAD.L	D1,D0	RR.L	D1,D4	LOAD.W	(A4+),D1	; destination <-- milieu	SWAP.W	D0	DECJ.W,NMO D3,52$; Effectue le travail de fin.60$:	AND.W	D2,#H'000F	JUMP,EQ 80$	SL.W	D2,#1	LOAD.W	D5,(A1)+(D2.W)	; D5 <-- masque	LOAD.W	D0,(A3)	RR.L	D0,D4	LOAD.W	D1,(A4)	AND.W	D1,D5	NOT.W	D5	AND.W	D0,D5	OR.W	D0,D1	LOAD.W	(A4),D0		; destination <-- fin	JUMP'	80$; Effectue le travail de dbut/fin.70$:	SUB.W	D2,#16	LOAD.W	D5,#H'FFFF72$:	ADD.W	D2,#16	SL.W	D2,#1	LOAD.W	D1,(A1)+(D2.W)	; D1 <-- masque	NOT.W	D1	AND.W	D5,D1		; D5 <-- masque le masque !	LOAD.W	D0,(A3)	RR.L	D0,D4	AND.W	D0,D5	NOT.W	D5	LOAD.W	D3,(A4)	AND.W	D3,D5	OR.W	D0,D3	LOAD.W	(A4),D0		; destination <-- dbut/fin;	JUMP	80$80$:	POPM.L	D2,D3,D4,A3,A4	ADD.L	A3,A5		; A3 <-- ajoute Iy source	ADD.L	A4,A6		; A4 <-- ajoute Iy destination	SUB.L	D2,#H'10000	LOAD.L	D1,D2	SWAP.W	D1	TEST.W	D1	JUMP,NE 20$	POPM.L	D0..D7,A0..A6	RET;------------\; RASTER_SET  >;============/; Dplace une surface rectangulaire mmoire/cran --> mmoire/cran.; in	A2.L	^description fentre;	----;	D3.L	coordonne source (y;x);	A3.L	^mmoire source/^nil si cran;	D5.W	Iy source (si mmoire);	----;	D4.L	coordonne destination (y;x);	A4.L	^mmoire destination/^nil si cran;	D6.W	Iy destination (si mmoire);	----;	D2.L	hauteur/largeur (y;x); out	-; mod	-RASTER_SET:	PUSHM.L	D0..D7,A0..A6	LOAD.L	D0,A3		; source dans l'cran ?	JUMP',NE 10$		; non => 10$				; oui =>	LOAD.L	A3,(A2)+ODFABS	; A3 <-- adresse dbut cran	LOAD.W	D5,(A2)+ODFIIY	; D5 <-- Iy cran	ADD.W	D3,(A2)+ODFWBX	; D3 <-- dans (sous-)fentre en X	SWAP.W	D3	ADD.W	D3,(A2)+ODFWBY	; D3 <-- dans (sous-)fentre en Y	SWAP.W	D310$:	LOAD.L	D0,D3	SWAP.W	D0	MUL.WU	D0,D5	ADD.L	A3,D0	LOAD.W	D0,D3	SR.W	D0,#3	ADD.W	A3,D0		; A3 <-- ^byte source	AND.W	D3,#H'0007	; D3 <-- Ds	LOAD.W	A5,D5		; A5 <-- Iy source	LOAD.L	D0,A4		; destination dans l'cran ?	JUMP',NE 15$		; non => 15$				; oui =>	LOAD.L	A4,(A2)+ODFABS	; A4 <-- adresse dbut cran	LOAD.W	D6,(A2)+ODFIIY	; D6 <-- Iy cran	ADD.W	D4,(A2)+ODFWBX	; D4 <-- dans (sous-)fentre en X	SWAP.W	D4	ADD.W	D4,(A2)+ODFWBY	; D4 <-- dans (sous-)fentre en Y	SWAP.W	D415$:	LOAD.L	D0,D4	SWAP.W	D0	MUL.WU	D0,D6	ADD.L	A4,D0	LOAD.W	D0,D4	SR.W	D0,#3	ADD.W	A4,D0		; A4 <-- ^byte destination	AND.W	D4,#H'0007	; D4 <-- Dd	LOAD.W	A6,D6		; A6 <-- Iy destination	LOAD.L	A1,#R16"TARASTER_MASK20$:	PUSHM.L	D2,D3,D4,A3,A4; Si l'adresse n'est pas paire, recule d'un byte.	LOAD.W	D0,A3	RR.W	D0,#1	JUMP',CC 30$	DEC.L	A3		; A3 <-- adresse paire	ADD.W	D3,#8		; D3 <-- Ds30$:	LOAD.W	D0,A4	RR.W	D0,#1	JUMP',CC 32$	DEC.L	A4		; A4 <-- adresse paire	ADD.W	D4,#8		; D4 <-- Dd32$:; Effectue le travail de dbut.	LOAD.W	D0,D3	OR.W	D0,D4	JUMP',NE 40$	COMP.W	D2,#16	JUMP,LO 70$	JUMP	50$40$:	LOAD.W	D0,D4	SL.W	D0,#1	LOAD.W	D5,(A1)+(D0.W)	; D5 <-- masque	LOAD.W	D1,D4	SUB.W	D4,D3		; D4 <-- Dm	JUMP',HS 44$	ADD.W	D4,#16		; D4 <-- Dm	LOAD.W	D0,(A3+)	SWAP.W	D044$:	ADD.W	D2,D1	SUB.W	D2,#16		; D2 <-- largeur restante	JUMP,LO 72$	LOAD.W	D0,(A3+)	LOAD.L	D1,D0	RR.L	D1,D4	AND.W	D1,D5	OR.W	(A4+),D1	; destination <-- dbut	SWAP.W	D0; Effectue le travail du milieu.50$:	LOAD.W	D3,D2	SR.W	D3,#4		; D3 <-- nb de words	JUMP',EQ 60$	DEC.W	D3		; D3 <-- -1  cause NMO52$:	LOAD.W	D0,(A3+)	LOAD.L	D1,D0	RR.L	D1,D4	OR.W	(A4+),D1	; destination <-- milieu	SWAP.W	D0	DECJ.W,NMO D3,52$; Effectue le travail de fin.60$:	AND.W	D2,#H'000F	JUMP,EQ 80$	SL.W	D2,#1	LOAD.W	D5,(A1)+(D2.W)	; D5 <-- masque	LOAD.W	D0,(A3)	RR.L	D0,D4	NOT.W	D5	AND.W	D0,D5	OR.W	(A4),D0		; destination <-- fin	JUMP'	80$; Effectue le travail de dbut/fin.70$:	SUB.W	D2,#16	LOAD.W	D5,#H'FFFF72$:	ADD.W	D2,#16	SL.W	D2,#1	LOAD.W	D1,(A1)+(D2.W)	; D1 <-- masque	NOT.W	D1	AND.W	D5,D1		; D5 <-- masque le masque !	LOAD.W	D0,(A3)	RR.L	D0,D4	AND.W	D0,D5	OR.W	(A4),D0		; destination <-- dbut/fin;	JUMP	80$80$:	POPM.L	D2,D3,D4,A3,A4	ADD.L	A3,A5		; A3 <-- ajoute Iy source	ADD.L	A4,A6		; A4 <-- ajoute Iy destination	SUB.L	D2,#H'10000	LOAD.L	D1,D2	SWAP.W	D1	TEST.W	D1	JUMP,NE 20$	POPM.L	D0..D7,A0..A6	RET;------------\; RASTER_INV  >;============/; Dplace une surface rectangulaire mmoire/cran --> mmoire/cran.; in	A2.L	^description fentre;	----;	D3.L	coordonne source (y;x);	A3.L	^mmoire source/^nil si cran;	D5.W	Iy source (si mmoire);	----;	D4.L	coordonne destination (y;x);	A4.L	^mmoire destination/^nil si cran;	D6.W	Iy destination (si mmoire);	----;	D2.L	hauteur/largeur (y;x); out	-; mod	-RASTER_INV:	PUSHM.L	D0..D7,A0..A6	LOAD.L	D0,A3		; source dans l'cran ?	JUMP',NE 10$		; non => 10$				; oui =>	LOAD.L	A3,(A2)+ODFABS	; A3 <-- adresse dbut cran	LOAD.W	D5,(A2)+ODFIIY	; D5 <-- Iy cran	ADD.W	D3,(A2)+ODFWBX	; D3 <-- dans (sous-)fentre en X	SWAP.W	D3	ADD.W	D3,(A2)+ODFWBY	; D3 <-- dans (sous-)fentre en Y	SWAP.W	D310$:	LOAD.L	D0,D3	SWAP.W	D0	MUL.WU	D0,D5	ADD.L	A3,D0	LOAD.W	D0,D3	SR.W	D0,#3	ADD.W	A3,D0		; A3 <-- ^byte source	AND.W	D3,#H'0007	; D3 <-- Ds	LOAD.W	A5,D5		; A5 <-- Iy source	LOAD.L	D0,A4		; destination dans l'cran ?	JUMP',NE 15$		; non => 15$				; oui =>	LOAD.L	A4,(A2)+ODFABS	; A4 <-- adresse dbut cran	LOAD.W	D6,(A2)+ODFIIY	; D6 <-- Iy cran	ADD.W	D4,(A2)+ODFWBX	; D4 <-- dans (sous-)fentre en X	SWAP.W	D4	ADD.W	D4,(A2)+ODFWBY	; D4 <-- dans (sous-)fentre en Y	SWAP.W	D415$:	LOAD.L	D0,D4	SWAP.W	D0	MUL.WU	D0,D6	ADD.L	A4,D0	LOAD.W	D0,D4	SR.W	D0,#3	ADD.W	A4,D0		; A4 <-- ^byte destination	AND.W	D4,#H'0007	; D4 <-- Dd	LOAD.W	A6,D6		; A6 <-- Iy destination	LOAD.L	A1,#R16"TARASTER_MASK20$:	PUSHM.L	D2,D3,D4,A3,A4; Si l'adresse n'est pas paire, recule d'un byte.	LOAD.W	D0,A3	RR.W	D0,#1	JUMP',CC 30$	DEC.L	A3		; A3 <-- adresse paire	ADD.W	D3,#8		; D3 <-- Ds30$:	LOAD.W	D0,A4	RR.W	D0,#1	JUMP',CC 32$	DEC.L	A4		; A4 <-- adresse paire	ADD.W	D4,#8		; D4 <-- Dd32$:; Effectue le travail de dbut.	LOAD.W	D0,D3	OR.W	D0,D4	JUMP',NE 40$	COMP.W	D2,#16	JUMP,LO 70$	JUMP	50$40$:	LOAD.W	D0,D4	SL.W	D0,#1	LOAD.W	D5,(A1)+(D0.W)	; D5 <-- masque	LOAD.W	D1,D4	SUB.W	D4,D3		; D4 <-- Dm	JUMP',HS 44$	ADD.W	D4,#16		; D4 <-- Dm	LOAD.W	D0,(A3+)	SWAP.W	D044$:	ADD.W	D2,D1	SUB.W	D2,#16		; D2 <-- largeur restante	JUMP,LO 72$	LOAD.W	D0,(A3+)	LOAD.L	D1,D0	RR.L	D1,D4	AND.W	D1,D5	XOR.W	(A4+),D1	; destination <-- dbut	SWAP.W	D0; Effectue le travail du milieu.50$:	LOAD.W	D3,D2	SR.W	D3,#4		; D3 <-- nb de words	JUMP',EQ 60$	DEC.W	D3		; D3 <-- -1  cause NMO52$:	LOAD.W	D0,(A3+)	LOAD.L	D1,D0	RR.L	D1,D4	XOR.W	(A4+),D1	; destination <-- milieu	SWAP.W	D0	DECJ.W,NMO D3,52$; Effectue le travail de fin.60$:	AND.W	D2,#H'000F	JUMP,EQ 80$	SL.W	D2,#1	LOAD.W	D5,(A1)+(D2.W)	; D5 <-- masque	LOAD.W	D0,(A3)	RR.L	D0,D4	NOT.W	D5	AND.W	D0,D5	XOR.W	(A4),D0		; destination <-- fin	JUMP'	80$; Effectue le travail de dbut/fin.70$:	SUB.W	D2,#16	LOAD.W	D5,#H'FFFF72$:	ADD.W	D2,#16	SL.W	D2,#1	LOAD.W	D1,(A1)+(D2.W)	; D1 <-- masque	NOT.W	D1	AND.W	D5,D1		; D5 <-- masque le masque !	LOAD.W	D0,(A3)	RR.L	D0,D4	AND.W	D0,D5	XOR.W	(A4),D0		; destination <-- dbut/fin;	JUMP	80$80$:	POPM.L	D2,D3,D4,A3,A4	ADD.L	A3,A5		; A3 <-- ajoute Iy source	ADD.L	A4,A6		; A4 <-- ajoute Iy destination	SUB.L	D2,#H'10000	LOAD.L	D1,D2	SWAP.W	D1	TEST.W	D1	JUMP,NE 20$	POPM.L	D0..D7,A0..A6	RET;-------------\; RASTER_CLEAR >;=============/; Dplace une surface rectangulaire mmoire/cran --> mmoire/cran.; in	A2.L	^description fentre;	----;	D3.L	coordonne source (y;x);	A3.L	^mmoire source/^nil si cran;	D5.W	Iy source (si mmoire);	----;	D4.L	coordonne destination (y;x);	A4.L	^mmoire destination/^nil si cran;	D6.W	Iy destination (si mmoire);	----;	D2.L	hauteur/largeur (y;x); out	-; mod	-RASTER_CLEAR:	PUSHM.L	D0..D7,A0..A6	LOAD.L	D0,A3		; source dans l'cran ?	JUMP',NE 10$		; non => 10$				; oui =>	LOAD.L	A3,(A2)+ODFABS	; A3 <-- adresse dbut cran	LOAD.W	D5,(A2)+ODFIIY	; D5 <-- Iy cran	ADD.W	D3,(A2)+ODFWBX	; D3 <-- dans (sous-)fentre en X	SWAP.W	D3	ADD.W	D3,(A2)+ODFWBY	; D3 <-- dans (sous-)fentre en Y	SWAP.W	D310$:	LOAD.L	D0,D3	SWAP.W	D0	MUL.WU	D0,D5	ADD.L	A3,D0	LOAD.W	D0,D3	SR.W	D0,#3	ADD.W	A3,D0		; A3 <-- ^byte source	AND.W	D3,#H'0007	; D3 <-- Ds	LOAD.W	A5,D5		; A5 <-- Iy source	LOAD.L	D0,A4		; destination dans l'cran ?	JUMP',NE 15$		; non => 15$				; oui =>	LOAD.L	A4,(A2)+ODFABS	; A4 <-- adresse dbut cran	LOAD.W	D6,(A2)+ODFIIY	; D6 <-- Iy cran	ADD.W	D4,(A2)+ODFWBX	; D4 <-- dans (sous-)fentre en X	SWAP.W	D4	ADD.W	D4,(A2)+ODFWBY	; D4 <-- dans (sous-)fentre en Y	SWAP.W	D415$:	LOAD.L	D0,D4	SWAP.W	D0	MUL.WU	D0,D6	ADD.L	A4,D0	LOAD.W	D0,D4	SR.W	D0,#3	ADD.W	A4,D0		; A4 <-- ^byte destination	AND.W	D4,#H'0007	; D4 <-- Dd	LOAD.W	A6,D6		; A6 <-- Iy destination	LOAD.L	A1,#R16"TARASTER_MASK20$:	PUSHM.L	D2,D3,D4,A3,A4; Si l'adresse n'est pas paire, recule d'un byte.	LOAD.W	D0,A3	RR.W	D0,#1	JUMP',CC 30$	DEC.L	A3		; A3 <-- adresse paire	ADD.W	D3,#8		; D3 <-- Ds30$:	LOAD.W	D0,A4	RR.W	D0,#1	JUMP',CC 32$	DEC.L	A4		; A4 <-- adresse paire	ADD.W	D4,#8		; D4 <-- Dd32$:; Effectue le travail de dbut.	LOAD.W	D0,D3	OR.W	D0,D4	JUMP',NE 40$	COMP.W	D2,#16	JUMP,LO 70$	JUMP	50$40$:	LOAD.W	D0,D4	SL.W	D0,#1	LOAD.W	D5,(A1)+(D0.W)	; D5 <-- masque	LOAD.W	D1,D4	SUB.W	D4,D3		; D4 <-- Dm	JUMP',HS 44$	ADD.W	D4,#16		; D4 <-- Dm	LOAD.W	D0,(A3+)	SWAP.W	D044$:	ADD.W	D2,D1	SUB.W	D2,#16		; D2 <-- largeur restante	JUMP,LO 72$	LOAD.W	D0,(A3+)	LOAD.L	D1,D0	RR.L	D1,D4	AND.W	D1,D5	NOT.W	D1	AND.W	(A4+),D1	; destination <-- dbut	SWAP.W	D0; Effectue le travail du milieu.50$:	LOAD.W	D3,D2	SR.W	D3,#4		; D3 <-- nb de words	JUMP',EQ 60$	DEC.W	D3		; D3 <-- -1  cause NMO52$:	LOAD.W	D0,(A3+)	LOAD.L	D1,D0	RR.L	D1,D4	NOT.W	D1	AND.W	(A4+),D1	; destination <-- milieu	SWAP.W	D0	DECJ.W,NMO D3,52$; Effectue le travail de fin.60$:	AND.W	D2,#H'000F	JUMP,EQ 80$	SL.W	D2,#1	LOAD.W	D5,(A1)+(D2.W)	; D5 <-- masque	LOAD.W	D0,(A3)	RR.L	D0,D4	NOT.W	D5	AND.W	D0,D5	NOT.W	D0	AND.W	(A4),D0		; destination <-- fin	JUMP'	80$; Effectue le travail de dbut/fin.70$:	SUB.W	D2,#16	LOAD.W	D5,#H'FFFF72$:	ADD.W	D2,#16	SL.W	D2,#1	LOAD.W	D1,(A1)+(D2.W)	; D1 <-- masque	NOT.W	D1	AND.W	D5,D1		; D5 <-- masque le masque !	LOAD.W	D0,(A3)	RR.L	D0,D4	AND.W	D0,D5	NOT.W	D0	AND.W	(A4),D0		; destination <-- dbut/fin;	JUMP	80$80$:	POPM.L	D2,D3,D4,A3,A4	ADD.L	A3,A5		; A3 <-- ajoute Iy source	ADD.L	A4,A6		; A4 <-- ajoute Iy destination	SUB.L	D2,#H'10000	LOAD.L	D1,D2	SWAP.W	D1	TEST.W	D1	JUMP,NE 20$	POPM.L	D0..D7,A0..A6	RETTARASTER_MASK:	.W	B'1111111111111111	.W	B'0111111111111111	.W	B'0011111111111111	.W	B'0001111111111111	.W	B'0000111111111111	.W	B'0000011111111111	.W	B'0000001111111111	.W	B'0000000111111111	.W	B'0000000011111111	.W	B'0000000001111111	.W	B'0000000000111111	.W	B'0000000000011111	.W	B'0000000000001111	.W	B'0000000000000111	.W	B'0000000000000011	.W	B'0000000000000001	.EVENVAR:	.FILLB	LGVAR,0	.END	START